code.C:
#include <stdio.h>
#include <stdlib.h>

struct TreeNode {
   int val;
   struct TreeNode *left;
   struct TreeNode *right;
};

int floorBST(struct TreeNode* root, int target) {
   int floor = -1;
   while (root) {
      if (root->val == target) {
         floor = root->val;
         break;
      } else if (root->val < target) {
         floor = root->val;
         root = root->right;
      } else {
         root = root->left;
      }
   }
   return floor;
}

