code.Java:
public class Solution {
   public int floorBST(TreeNode root, int target) {
      int floor = -1;
      while (root != null) {
         if (root.val == target) {
            floor = root.val;
            break;
         } else if (root.val < target) {
            floor = root.val;
            root = root.right;
         } else {
            root = root.left;
         }
      }
      return floor;
   }
}

